import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { EnvService } from "src/app/core/services/env.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { IGender } from "../../Models/References/Gender";
import { Policy } from "../../Models/Users/Policy";
import { UserInfo } from "src/app/core/models/UserInfo";
import { FeaturesAuthService } from "src/app/core/services/AuthenticationServices/features-auth.service";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";
import { BranchReference } from "../../Models/Settings/BranchReference";
import { IOfficer, officerResponseModal } from "../../Models/Officer/Officer";
import { OfficerService } from "src/app/core/services/officer.service";
import { AlertService } from "src/app/core/services/alert.service";
import { format } from "date-fns";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
@Component({
  selector: "app-add-user",
  templateUrl: "./add-user.page.html",
  styleUrls: ["./add-user.page.scss"],
})
export class AddUserPage implements OnInit {
  [x: string]: any;
  personalFormStatus: boolean = false;
  constructor(
    private http: HttpClient,
    private env: EnvService,
    private referencesService: ReferencesService,
    private FormBuilder: FormBuilder,
    private authService: MohassilAuthService,
    private alertService: AlertService,
    private OfficerService: OfficerService,
    public inputMaskingService: InputMaskingService
  ) {}

  Genders: IGender[];

  Policy: Policy[];
  BRData: BranchReference[];
  userInfo: UserInfo;
  Officer: officerResponseModal[];
  PersonalFormValid: Boolean;
  PromiseOff: Promise<officerResponseModal[]>;
  personalForm: FormGroup = this.FormBuilder.group({
    user_name: [null, [Validators.required]],
    full_name: [null, [Validators.required]],
    nation_id: [null],
    job_code: [null],
    password: [null, [Validators.required]],
    re_password: [null, [Validators.required]],
    mobile1: [null],
    mobile2: [null],
    client_code: [null],
    type: [null, [Validators.required]],
    mail: [null],
    Officerkey: [null],
    loan_am_req: [null, [Validators.required]],
    loan_no_req: [null, [Validators.required]],

    StartingWorkingDate: [
      format(new Date().setDate(0), "yyyy-MM-dd"),
      [Validators.required],
    ],
    Policycode: [null, [Validators.required]],
    UserBrcode: [null, [Validators.required]],
    EndWorkingDate: [format(new Date("01-01-2050"), "yyyy-MM-dd")],

    MoveWorkingDate: [null],
    NextWorkingDate: [null],
    StartDate: [null],
  });

  async ngOnInit(): Promise<void> {
    this.Genders = await this.referencesService.getGender();
    this.userInfo = await this.authService.getUserInfo();
    this.PersonalFormValid = false;
    this.getOfficersByBranchCode();
    this.personalFormStatus = true;
    this.GetuserPolicy(Number(this.userInfo.org_code));
    this.GetbranchByUser(this.userInfo.user_name);
  }

  async GetuserPolicy(org_code: number) {
    //this.showLoader = true;
    this.Policy = await this.http
      .get<Policy[]>(
        this.env.API_URL + `api/Policy/GetuserPolicy?org_code=` + org_code
      )
      .toPromise();
    console.log("Test", this.Policy);
  }

  async GetbranchByUser(user_name: string) {
    //this.showLoader = true;
    this.BRData = await this.http
      .get<BranchReference[]>(
        this.env.API_URL + `api/Branch/GetbranchByUser?user_name=` + user_name
      )
      .toPromise();
    console.log("Test", this.Policy);
  }
  getOfficersByBranchCode = async (): Promise<officerResponseModal[]> => {
    try {
      console.log("br", this.personalForm.value.userBrcode);
      this.showLoader = true;
      const response = await this.http
        .get<officerResponseModal[]>(
          this.env.API_URL +
            `api/Officer/GetBranchOfficers?branch_code=${this.personalForm.value.UserBrcode}`,
          {}
        )
        .toPromise();
      {
        this.Officer = response;
      }
      this.showLoader = false;
      this.disableOfficerButt = false;

      return response;
    } catch (error) {
      console.error("Error", error);
      throw error;
    }
  };

  async SaveUser() {
    if (this.personalForm.valid) {
      if (
        this.personalForm.value.password == this.personalForm.value.re_password
      ) {
        this.http
          .post(this.env.API_URL + "api/User/AddUser", {
            user_name: this.personalForm.value.user_name,
            full_name: this.personalForm.value.full_name,
            nation_id: this.personalForm.value.nation_id,
            job_code: this.personalForm.value.job_code,
            password: this.personalForm.value.password,
            re_password: this.personalForm.value.re_password,
            hashed_password: this.personalForm.value.re_password,
            mobile1:
              this.personalForm.value.mobile1 === null
                ? ""
                : this.personalForm.value.mobile1.toString(),
            mobile2:
              this.personalForm.value.mobile2 === null
                ? ""
                : this.personalForm.value.mobile2.toString(),
            client_code: this.personalForm.value.client_code,
            type: this.personalForm.value.type,
            mail: this.personalForm.value.mail,
            Officerkey: this.personalForm.value.Officerkey,
            loan_am_req: this.personalForm.value.loan_am_req,
            loan_no_req: this.personalForm.value.loan_no_req,

            startingWorkingDate: this.personalForm.value.StartingWorkingDate,
            Policycode: this.personalForm.value.Policycode,
            userBrcode: this.personalForm.value.UserBrcode,
            endWorkingDate: this.personalForm.value.EndWorkingDate,

            moveWorkingDate: this.personalForm.value.MoveWorkingDate,
            nextWorkingDate: this.personalForm.value.NextWorkingDate,
            startDate: this.personalForm.value.StartDate,
          })
          .subscribe({
            next: (data) => {
              this.alertService.showAlertConfirm("تم الحفظ بنجاح", false);
              //this.ViewDocument();
              this.personalForm.reset();
              this.PersonalFormValid = false;
            },
            error: (err) => {
              console.log(err);
              this.alertService.showAlertError(err.error, false);
            },
          });
      } else {
        this.alertService.showAlertError("كلمة المرور غير متطابقة", false);
      }
      this.PersonalFormValid = true;
    } else {
      this.alertService.showAlertError("يجب ادخال البيانات", false);
      this.PersonalFormValid = true;
    }
  }
}
